	Describe("Redact", func() {
		Describe("Subsonic API password", func() {
			msg := "getLyrics.view?v=1.2.0&c=iSub&u=user_name&p=first%20and%20other%20words&title=Title"
			Expect(Redact(msg)).To(Equal("getLyrics.view?v=1.2.0&c=iSub&u=user_name&p=[REDACTED]&title=Title"))
		})
	})

	Describe("WindowsLineEndingFormatter", func() {
		var formatter *WindowsLineEndingFormatter
		var innerFormatter logrus.Formatter

		BeforeEach(func() {
			innerFormatter = &logrus.TextFormatter{
				DisableColors:    true,
				DisableTimestamp: true,
				DisableSorting:   true,
			}
			formatter = NewWindowsLineEndingFormatter(innerFormatter)
		})

		It("preserves existing CRLF without double-conversion", func() {
			mockFormatter := &mockFormatter{output: "test\r\n"}
			windowsFormatter := NewWindowsLineEndingFormatter(mockFormatter)

			entry := &logrus.Entry{
				Message: "test",
				Level:   logrus.InfoLevel,
			}

			result, err := windowsFormatter.Format(entry)
			Expect(err).To(BeNil())

			// Should have exactly one CRLF, not double-converted to \r\r\n
			Expect(string(result)).To(Equal("test\r\n"))
		})

		It("converts multiple LF to CRLF", func() {
			mockFormatter := &mockFormatter{output: "line1\nline2\nline3\n"}
			windowsFormatter := NewWindowsLineEndingFormatter(mockFormatter)

			entry := &logrus.Entry{
				Message: "test",
				Level:   logrus.InfoLevel,
			}

			result, err := windowsFormatter.Format(entry)
			Expect(err).To(BeNil())
			// The formatter only applies on Windows, so check based on runtime
			// For the test, we verify the logic works as expected
			outputStr := string(result)
			Expect(outputStr).To(ContainSubstring("line1"))
			Expect(outputStr).To(ContainSubstring("line2"))
			Expect(outputStr).To(ContainSubstring("line3"))
		})

		It("handles mixed CRLF and LF correctly", func() {
			mockFormatter := &mockFormatter{output: "line1\r\nline2\nline3\r\nline4\n"}
			windowsFormatter := NewWindowsLineEndingFormatter(mockFormatter)

			entry := &logrus.Entry{
				Message: "test",
				Level:   logrus.InfoLevel,
			}

			result, err := windowsFormatter.Format(entry)
			Expect(err).To(BeNil())
			outputStr := string(result)
			// Verify all lines are present
			Expect(outputStr).To(ContainSubstring("line1"))
			Expect(outputStr).To(ContainSubstring("line2"))
			Expect(outputStr).To(ContainSubstring("line3"))
			Expect(outputStr).To(ContainSubstring("line4"))
		})

		It("passes errors from inner formatter", func() {
			errorFormatter := &errorMockFormatter{shouldError: true}
			windowsFormatter := NewWindowsLineEndingFormatter(errorFormatter)

			entry := &logrus.Entry{
				Message: "test",
				Level:   logrus.InfoLevel,
			}

			_, err := windowsFormatter.Format(entry)
			Expect(err).NotTo(BeNil())
		})
	})
})

